    <p style="margin:12px 0 0;font-size:12px;color:rgba(0,0,0,0.6);"><a href="${SITE.URL}/orders" style="color:#2d1a14;font-weight:800;text-decoration:none;">${enInfo.cta} →</a></p>
  `);

  return sendEmail({
    to: params.to,
