    html: baseTemplate(`تحديث الطلب #${params.orderRef} / Order Update`, content + enMirror),
    text: `تحديث طلبك #${params.orderRef}: ${cfg.badgeText}\nOrder #${params.orderRef} status: ${enInfo.title}`,
